//=====================================================
// MODEL AND VIEW METHOD summary M_OR2
//=====================================================

 SimpleDateFormat dateformat =
         new SimpleDateFormat("dd-MMM-yyyy");
		 
		 
public ModelAndView getM_OR2View(
        String reportId,
        String fromdate,
        String todate,
        String currency,
        String dtltype,
        Pageable pageable,
        String type,
        BigDecimal version,HttpServletRequest req1,Model md) {

    ModelAndView mv = new ModelAndView();
	
	 String userid = (String) req1.getSession().getAttribute("USERID");
	    System.out.println("User Id Maker and Checker: " + userid);
	    String role = userProfileRep.getUserRole(userid);
	    md.addAttribute("role", role);
	    System.out.println("Role: " + role);
		
		int pageSize = pageable.getPageSize();
	    int currentPage = pageable.getPageNumber();
	    int startItem = currentPage * pageSize;

    System.out.println("M_OR2 View Called");
    System.out.println("Type = " + type);
    System.out.println("Version = " + version);
    System.out.println("DtlType = " + dtltype);

    try {

        Date dt = dateformat.parse(todate);

        // =====================================================
        // DETAIL
        // =====================================================

        if ("detail".equalsIgnoreCase(dtltype)) {

            // ARCHIVAL DETAIL
            if ("ARCHIVAL".equalsIgnoreCase(type) && version != null) {

                List<M_OR2_Archival_Detail_Entity> T1Master =
                        getDetaildatabydateListarchival(dt, version);

                System.out.println("Archival Detail Size = " + T1Master.size());

                mv.addObject("reportsummary", T1Master);
                mv.addObject("displaymode", "detail");
            }

            // RESUB DETAIL
            else if ("RESUB".equalsIgnoreCase(type) && version != null) {

                List<M_OR2_RESUB_Detail_Entity> T1Master =
                        getResubDetaildatabydateList(dt, version);

                System.out.println("Resub Detail Size = " + T1Master.size());

                mv.addObject("reportsummary", T1Master);
                 mv.addObject("displaymode", "resub");
            }

            // NORMAL DETAIL
            else {

                List<M_OR2_Detail_Entity> T1Master =
                        getDetaildatabydateList(dt);

                System.out.println("Normal Detail Size = " + T1Master.size());

                mv.addObject("reportsummary", T1Master);
                mv.addObject("displaymode", "detail");
            }
        }

        // =====================================================
        // SUMMARY
        // =====================================================

        else {

            // ARCHIVAL SUMMARY
            if ("ARCHIVAL".equalsIgnoreCase(type) && version != null) {

                List<M_OR2_Archival_Summary_Entity> T1Master =
                        getDataByDateListArchival(dt, version);

                System.out.println("Archival Summary Size = " + T1Master.size());

                mv.addObject("reportsummary", T1Master);
				mv.addObject("displaymode", "summary");
            }

            // RESUB SUMMARY
            else if ("RESUB".equalsIgnoreCase(type) && version != null) {

                List<M_OR2_RESUB_Summary_Entity> T1Master =
                        getResubSummarydatabydateListarchival(dt, version);

                System.out.println("Resub Summary Size = " + T1Master.size());

                mv.addObject("reportsummary", T1Master);
				  mv.addObject("displaymode", "resub");
            }

            // NORMAL SUMMARY
            else {

                List<M_OR2_Summary_Entity> T1Master =
                        getSummaryDataByDate(dt);

                System.out.println("Normal Summary Size = " + T1Master.size());

                mv.addObject("reportsummary", T1Master);
				 mv.addObject("displaymode", "summary");
            }

           
        }

        mv.addObject("report_date", dateformat.format(dt));

    } catch (Exception e) {
        e.printStackTrace();
    }

    mv.setViewName("BRRS/M_OR2");

    System.out.println("View Loaded : " + mv.getViewName());

    return mv;
}
	
	
