@Transactional
public void updateResubReport(M_OR2_RESUB_Summary_Entity updatedEntity) {

    System.out.println("Came to M_OR2 Resub Update");

    Date reportDate = updatedEntity.getReport_date();

    BigDecimal maxVersion = findMaxVersion(reportDate);

    if (maxVersion == null) {
        throw new RuntimeException(
                "No record found for REPORT_DATE : " + reportDate);
    }

    BigDecimal newVersion = maxVersion.add(BigDecimal.ONE);

    Date now = new Date();

    // ================================
    // RESUB SUMMARY
    // ================================
    M_OR2_RESUB_Summary_Entity resubSummary =
            new M_OR2_RESUB_Summary_Entity();

    BeanUtils.copyProperties(updatedEntity, resubSummary);

    resubSummary.setReport_date(reportDate);
    resubSummary.setReport_version(newVersion);
    resubSummary.setReportResubDate(now);

    // ================================
    // RESUB DETAIL
    // ================================
    M_OR2_RESUB_Detail_Entity resubDetail =
            new M_OR2_RESUB_Detail_Entity();

    BeanUtils.copyProperties(updatedEntity, resubDetail);

    resubDetail.setReport_date(reportDate);
    resubDetail.setReport_version(newVersion);
    resubDetail.setReportResubDate(now);

    // ================================
    // ARCHIVAL SUMMARY
    // ================================
    M_OR2_Archival_Summary_Entity archivalSummary =
            new M_OR2_Archival_Summary_Entity();

    BeanUtils.copyProperties(updatedEntity, archivalSummary);

    archivalSummary.setReport_date(reportDate);
    archivalSummary.setReport_version(newVersion);
    archivalSummary.setReportResubDate(now);

    // ================================
    // ARCHIVAL DETAIL
    // ================================
    M_OR2_Archival_Detail_Entity archivalDetail =
            new M_OR2_Archival_Detail_Entity();

    BeanUtils.copyProperties(updatedEntity, archivalDetail);

    archivalDetail.setReport_date(reportDate);
    archivalDetail.setReport_version(newVersion);
    archivalDetail.setReportResubDate(now);

    // ================================
    // INSERT RESUB SUMMARY
    // ================================
    try {
        insertResubSummary(resubSummary);
        System.out.println("Resub Summary Inserted");
    } catch (Exception e) {
        System.out.println("Skipped Resub Summary : " + e.getMessage());
        e.printStackTrace();
    }

    // ================================
    // INSERT RESUB DETAIL
    // ================================
    try {
        insertResubDetail(resubDetail);
        System.out.println("Resub Detail Inserted");
    } catch (Exception e) {
      
        e.printStackTrace();
    }

    // ================================
    // INSERT ARCHIVAL SUMMARY
    // ================================
    try {
        insertArchivalSummary(archivalSummary);
        System.out.println("Archival Summary Inserted");
    } catch (Exception e) {
       
        e.printStackTrace();
    }

    // ================================
    // INSERT ARCHIVAL DETAIL
    // ================================
    try {
        insertArchivalDetail(archivalDetail);
        System.out.println("Archival Detail Inserted");
    } catch (Exception e) {
       
        e.printStackTrace();
    }

    System.out.println("M_OR2 Resub Version Process Completed : " + newVersion);
}

private Object getValue(Object obj, String methodName) {
    try {
        return obj.getClass().getMethod(methodName).invoke(obj);
    } catch (Exception e) {
        throw new RuntimeException(e);
    }
}

